SELECT user_id, name, email
FROM users
WHERE user_id = #{userId}
  AND password = #{password}

SELECT user_id, name, email
FROM users
WHERE 1 = 1

    AND user_id = #{userId}

AND name = #{name}
AND email = #{email}

SELECT IF(COUNT(USER_ID) > 0, 'Y', 'N') AS EXISTS_YN
FROM users
WHERE USER_ID = #{userId}

SELECT IF(COUNT(USER_ID) > 0, 'Y', 'N') AS EXISTS_YN
FROM users
WHERE EMAIL = #{email}
